import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Trouver des mods fiables","description":"Un guide pour trouver des mods Fabric depuis des sources fiables.","frontmatter":{"title":"Trouver des mods fiables","description":"Un guide pour trouver des mods Fabric depuis des sources fiables.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"fr_fr/1.20.4/players/finding-mods.md","filePath":"versions/1.20.4/translated/fr_fr/players/finding-mods.md","lastUpdated":1739538073000}`);var a={name:`fr_fr/1.20.4/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Trouver des mods fiables <a class="header-anchor" href="#h1" aria-label="Permalink to “Trouver des mods fiables”">​</a></h1><p>La fiabilité d&#39;une source est subjective, et vous devriez toujours juger de par vous-même lorsque vous téléchargez des mods. Mais voici quelques astuces pour vous aider à trouver des mods fiables.</p><h2 id="_1-utiliser-une-source-connue-pour-etre-fiable" tabindex="-1">1. Utiliser une source connue pour être fiable <a class="header-anchor" href="#_1-utiliser-une-source-connue-pour-etre-fiable" aria-label="Permalink to “1. Utiliser une source connue pour être fiable”">​</a></h2><p>La majorité des mods sont publiés sur <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> ou <a href="https://www.curseforge.com/minecraft/search?page=1&amp;pageSize=20&amp;sortType=1&amp;class=mc-mods&amp;gameFlavorsIds=4" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Ces sites vérifient que les mods sont bel et bien ce qu&#39;ils prétendent être, et qu&#39;ils ne contiennent pas de code malicieux. Vous pouvez également signaler les mods malicieux sur ces sites, et ces derniers prennent les choses en main relativement rapidement.</p><h2 id="_2-voyez-avec-d-autres-personnes" tabindex="-1">2. Voyez avec d&#39;autres personnes ! <a class="header-anchor" href="#_2-voyez-avec-d-autres-personnes" aria-label="Permalink to “2. Voyez avec d&#39;autres personnes !”">​</a></h2><p>Si vous téléchargez un mod d&#39;une source qui n&#39;est pas réputée pour être fiable, vous devriez voir avec d&#39;autres personnes si elles ont déjà téléchargé le mod depuis la même source, et si elles ont eu des problèmes avec.</p><p>Dans le doute, vous pouvez demander de l&#39;aide sur le <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">serveur Discord Fabric</a> (en anglais) dans le channel <code>#player-support</code>.</p><h2 id="_3-evitez-les-sites-de-malware" tabindex="-1">3. Évitez les sites de malware ! <a class="header-anchor" href="#_3-evitez-les-sites-de-malware" aria-label="Permalink to “3. Évitez les sites de malware !”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Les sites de malware ne sont pas une évidence pour tout le monde. Si vous n&#39;êtes pas sûr, vous devriez demander l&#39;opinion d&#39;autres personnes ou éviter le site entièrement et uniquement utiliser des sites de confiance, comme Modrinth et CurseForge.</p></div><p>Il y a plein de sites qui prétendent héberger des mods Minecraft, mais qui ne sont en réalité que des sites de malware. Vous devriez les éviter à tout prix.</p><p>Vous pouvez utiliser des logiciels et sites antivirus comme <a href="https://www.microsoft.com/en-us/windows/windows-defender" target="_blank" rel="noreferrer">Windows Defender</a> ou <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> pour vérifier les mods que vous avez téléchargé. Mais cependant, ne vous fiez pas uniquement à ces méthodes, car elles peuvent parfois être incorrectes.</p><p>Pour rappel, si vous avez un doute, vous êtes le/la bienvenu(e) sur le <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">serveur Discord Fabric</a> pour demander de l&#39;aide dans le channel <code>#player-support</code>.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};